INSERT INTO public.spells (id, name, owner_id, source, visibility, level, school, casting_time, "range", components, duration, concentration, ritual, classes, description, higher_levels, save_type, attack_type, damage_dice, damage_type, damage_at_slot_level, damage_at_char_level, heal_dice, heal_at_slot_level, area_of_effect) VALUES
('glibness', 'Glibness', NULL, 'srd', 'private', 8, 'Transmutation', '1 action', 'Self', 'V', '1 hour', false, false, '{"Bard","Warlock","Psion"}', 'Until the spell ends, when you make a Charisma check, you can replace the number you roll with a 15. Additionally, no matter what you say, magic that would determine if you are telling the truth indicates that you are being truthful.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('holy-aura', 'Holy Aura', NULL, 'srd', 'private', 8, 'Abjuration', '1 action', 'Self', 'V, S, M (A tiny reliquary worth at least 1,000gp containing a sacred relic, such as a scrap of cloth from a saint''s robe or a piece of parchment from a religious text.)', 'Up to 1 minute', true, false, '{"Cleric"}', 'Divine light washes out from you and coalesces in a soft radiance in a 30-foot radius around you. Creatures of your choice in that radius when you cast this spell shed dim light in a 5-foot radius and have advantage on all saving throws, and other creatures have disadvantage on attack rolls against them until the spell ends. In addition, when a fiend or an undead hits an affected creature with a melee attack, the aura flashes with brilliant light. The attacker must succeed on a constitution saving throw or be blinded until the spell ends.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{"type":"sphere","size":30}'::jsonb),
('incendiary-cloud', 'Incendiary Cloud', NULL, 'srd', 'private', 8, 'Conjuration', '1 action', '150 feet', 'V, S', 'Up to 1 minute', true, false, '{"Sorcerer","Wizard"}', E'A swirling cloud of smoke shot through with white-hot embers appears in a 20-foot-radius sphere centered on a point within range. The cloud spreads around corners and is heavily obscured. It lasts for the duration or until a wind of moderate or greater speed (at least 10 miles per hour) disperses it.\n\nWhen the cloud appears, each creature in it must make a dexterity saving throw. A creature takes 10d8 fire damage on a failed save, or half as much damage on a successful one. A creature must also make this saving throw when it enters the spell''s area for the first time on a turn or ends its turn there.\n\nThe cloud moves 10 feet directly away from you in a direction that you choose at the start of each of your turns.', NULL, 'DEX', NULL, '10d8', 'Fire', '{"8":"10d8"}'::jsonb, NULL, NULL, NULL, '{"type":"sphere","size":20}'::jsonb),
('maze', 'Maze', NULL, 'srd', 'private', 8, 'Conjuration', '1 action', '60 feet', 'V, S', 'Up to 10 minutes', true, false, '{"Wizard","Psion"}', E'You banish a creature that you can see within range into a labyrinthine demiplane. The target remains there for the duration or until it escapes the maze.\n\nThe target can use its action to attempt to escape. When it does so, it makes a DC 20 Intelligence check. If it succeeds, it escapes, and the spell ends (a minotaur or goristro demon automatically succeeds).\n\nWhen the spell ends, the target reappears in the space it left or, if that space is occupied, in the nearest unoccupied space.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('mind-blank', 'Mind Blank', NULL, 'srd', 'private', 8, 'Abjuration', '1 action', 'Touch', 'V, S', '24 hours', false, false, '{"Bard","Wizard","Psion"}', 'Until the spell ends, one willing creature you touch is immune to psychic damage, any effect that would sense its emotions or read its thoughts, divination spells, and the charmed condition. The spell even foils wish spells and spells or effects of similar power used to affect the target''s mind or to gain information about the target.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('power-word-stun', 'Power Word Stun', NULL, 'srd', 'private', 8, 'Enchantment', '1 action', '60 feet', 'V', 'Instantaneous', false, false, '{"Bard","Sorcerer","Warlock","Wizard","Psion"}', E'You speak a word of power that can overwhelm the mind of one creature you can see within range, leaving it dumbfounded. If the target has 150 hit points or fewer, it is stunned. Otherwise, the spell has no effect.\n\nThe stunned target must make a constitution saving throw at the end of each of its turns. On a successful save, this stunning effect ends.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('sunburst', 'Sunburst', NULL, 'srd', 'private', 8, 'Evocation', '1 action', '150 feet', 'V, S, M (Fire and a piece of sunstone.)', 'Instantaneous', false, false, '{"Druid","Sorcerer","Wizard"}', E'Brilliant sunlight flashes in a 60-foot radius centered on a point you choose within range. Each creature in that light must make a constitution saving throw. On a failed save, a creature takes 12d6 radiant damage and is blinded for 1 minute. On a successful save, it takes half as much damage and isn''t blinded by this spell. Undead and oozes have disadvantage on this saving throw.\n\nA creature blinded by this spell makes another constitution saving throw at the end of each of its turns. On a successful save, it is no longer blinded.\n\nThis spell dispels any darkness in its area that was created by a spell.', NULL, 'CON', NULL, '12d6', 'Radiant', '{"8":"12d6"}'::jsonb, NULL, NULL, NULL, '{"type":"cylinder","size":60}'::jsonb),
('astral-projection', 'Astral Projection', NULL, 'srd', 'private', 9, 'Necromancy', '1 hour', '10 feet', 'V, S, M (For each creature you affect with this spell, you must provide one jacinth worth at least 1,000gp and one ornately carved bar of silver worth at least 100gp, all of which the spell consumes.)', 'Special', false, false, '{"Cleric","Warlock","Wizard","Psion"}', E'You and up to eight willing creatures within range project your astral bodies into the Astral Plane (the spell fails and the casting is wasted if you are already on that plane). The material body you leave behind is unconscious and in a state of suspended animation; it doesn''t need food or air and doesn''t age.\n\nYour astral body resembles your mortal form in almost every way, replicating your game statistics and possessions. The principal difference is the addition of a silvery cord that extends from between your shoulder blades and trails behind you, fading to invisibility after 1 foot. This cord is your tether to your material body. As long as the tether remains intact, you can find your way home. If the cord is cut--something that can happen only when an effect specifically states that it does--your soul and body are separated, killing you instantly.\n\nYour astral form can freely travel through the Astral Plane and can pass through portals there leading to any other plane. If you enter a new plane or return to the plane you were on when casting this spell, your body and possessions are transported along the silver cord, allowing you to re-enter your body as you enter the new plane. Your astral form is a separate incarnation. Any damage or other effects that apply to it have no effect on your physical body, nor do they persist when you return to it.\n\nThe spell ends for you and your companions when you use your action to dismiss it. When the spell ends, the affected creature returns to its physical body, and it awakens.\n\nThe spell might also end early for you or one of your companions. A successful dispel magic spell used against an astral or physical body ends the spell for that creature. If a creature''s original body or its astral form drops to 0 hit points, the spell ends for that creature. If the spell ends and the silver cord is intact, the cord pulls the creature''s astral form back to its body, ending its state of suspended animation.\n\nIf you are returned to your body prematurely, your companions remain in their astral forms and must find their own way back to their bodies, usually by dropping to 0 hit points.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('foresight', 'Foresight', NULL, 'srd', 'private', 9, 'Divination', '1 minute', 'Touch', 'V, S, M (A hummingbird feather.)', '8 hours', false, false, '{"Bard","Druid","Warlock","Wizard","Psion"}', E'You touch a willing creature and bestow a limited ability to see into the immediate future. For the duration, the target can''t be surprised and has advantage on attack rolls, ability checks, and saving throws. Additionally, other creatures have disadvantage on attack rolls against the target for the duration.\n\nThis spell immediately ends if you cast it again before its duration ends.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('gate', 'Gate', NULL, 'srd', 'private', 9, 'Conjuration', '1 action', '60 feet', 'V, S, M (A diamond worth at least 5,000gp.)', 'Up to 1 minute', true, false, '{"Cleric","Sorcerer","Wizard"}', E'You conjure a portal linking an unoccupied space you can see within range to a precise location on a different plane of existence. The portal is a circular opening, which you can make 5 to 20 feet in diameter. You can orient the portal in any direction you choose. The portal lasts for the duration.\n\nThe portal has a front and a back on each plane where it appears. Travel through the portal is possible only by moving through its front. Anything that does so is instantly transported to the other plane, appearing in the unoccupied space nearest to the portal.\n\nDeities and other planar rulers can prevent portals created by this spell from opening in their presence or anywhere within their domains.\n\nWhen you cast this spell, you can speak the name of a specific creature (a pseudonym, title, or nickname doesn''t work). If that creature is on a plane other than the one you are on, the portal opens in the named creature''s immediate vicinity and draws the creature through it to the nearest unoccupied space on your side of the portal. You gain no special power over the creature, and it is free to act as the GM deems appropriate. It might leave, attack you, or help you.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('imprisonment', 'Imprisonment', NULL, 'srd', 'private', 9, 'Abjuration', '1 minute', '30 feet', 'V, S, M (A vellum depiction or a carved statuette in the likeness of the target, and a special component that varies according to the version of the spell you choose, worth at least 500gp per Hit Die of the target.)', 'Until dispelled', false, false, '{"Warlock","Wizard"}', E'You create a magical restraint to hold a creature that you can see within range. The target must succeed on a wisdom saving throw or be bound by the spell; if it succeeds, it is immune to this spell if you cast it again. While affected by this spell, the creature doesn''t need to breathe, eat, or drink, and it doesn''t age. Divination spells can''t locate or perceive the target.\n\nWhen you cast the spell, you choose one of the following forms of imprisonment.\n\n***Burial.*** The target is entombed far beneath the earth in a sphere of magical force that is just large enough to contain the target. Nothing can pass through the sphere, nor can any creature teleport or use planar travel to get into or out of it.\n\nThe special component for this version of the spell is a small mithral orb.\n\n***Chaining.*** Heavy chains, firmly rooted in the ground, hold the target in place. The target is restrained until the spell ends, and it can''t move or be moved by any means until then.\n\nThe special component for this version of the spell is a fine chain of precious metal.\n\n***Hedged Prison.*** The spell transports the target into a tiny demiplane that is warded against teleportation and planar travel. The demiplane can be a labyrinth, a cage, a tower, or any similar confined structure or area of your choice.\n\nThe special component for this version of the spell is a miniature representation of the prison made from jade.\n\n***Minimus Containment.*** The target shrinks to a height of 1 inch and is imprisoned inside a gemstone or similar object. Light can pass through the gemstone normally (allowing the target to see out and other creatures to see in), but nothing else can pass through, even by means of teleportation or planar travel. The gemstone can''t be cut or broken while the spell remains in effect.\n\nThe special component for this version of the spell is a large, transparent gemstone, such as a corundum, diamond, or ruby.\n\n***Slumber.*** The target falls asleep and can''t be awoken.\n\nThe special component for this version of the spell consists of rare soporific herbs.\n\n***Ending the Spell.*** During the casting of the spell, in any of its versions, you can specify a condition that will cause the spell to end and release the target. The condition can be as specific or as elaborate as you choose, but the GM must agree that the condition is reasonable and has a likelihood of coming to pass. The conditions can be based on a creature''s name, identity, or deity but otherwise must be based on observable actions or qualities and not based on intangibles such as level, class, or hit points.\n\nA dispel magic spell can end the spell only if it is cast as a 9th-level spell, targeting either the prison or the special component used to create it.\n\nYou can use a particular special component to create only one prison at a time. If you cast the spell again using the same component, the target of the first casting is immediately freed from its binding.', NULL, 'WIS', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('mass-heal', 'Mass Heal', NULL, 'srd', 'private', 9, 'Conjuration', '1 action', '60 feet', 'V, S', 'Instantaneous', false, false, '{"Cleric"}', 'A flood of healing energy flows from you into injured creatures around you. You restore up to 700 hit points, divided as you choose among any number of creatures that you can see within range. Creatures healed by this spell are also cured of all diseases and any effect making them blinded or deafened. This spell has no effect on undead or constructs.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '700', '{"9":"700"}'::jsonb, NULL),
('meteor-swarm', 'Meteor Swarm', NULL, 'srd', 'private', 9, 'Evocation', '1 action', '1 mile', 'V, S', 'Instantaneous', false, false, '{"Sorcerer","Wizard"}', E'Blazing orbs of fire plummet to the ground at four different points you can see within range. Each creature in a 40-foot-radius sphere centered on each point you choose must make a dexterity saving throw. The sphere spreads around corners. A creature takes 20d6 fire damage and 20d6 bludgeoning damage on a failed save, or half as much damage on a successful one. A creature in the area of more than one fiery burst is affected only once.\n\nThe spell damages objects in the area and ignites flammable objects that aren''t being worn or carried.', NULL, 'DEX', NULL, '20d6 + 20d6', 'Fire', '{"9":"20d6 + 20d6"}'::jsonb, NULL, NULL, NULL, '{"type":"sphere","size":40}'::jsonb),
('power-word-kill', 'Power Word Kill', NULL, 'srd', 'private', 9, 'Enchantment', '1 action', '60 feet', 'V', 'Instantaneous', false, false, '{"Bard","Sorcerer","Warlock","Wizard"}', 'You utter a word of power that can compel one creature you can see within range to die instantly. If the creature you choose has 100 hit points or fewer, it dies. Otherwise, the spell has no effect.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('prismatic-wall', 'Prismatic Wall', NULL, 'srd', 'private', 9, 'Abjuration', '1 action', '60 feet', 'V, S', '10 minutes', false, false, '{"Wizard"}', E'A shimmering, multicolored plane of light forms a vertical opaque wall--up to 90 feet long, 30 feet high, and 1 inch thick--centered on a point you can see within range. Alternatively, you can shape the wall into a sphere up to 30 feet in diameter centered on a point you choose within range. The wall remains in place for the duration. If you position the wall so that it passes through a space occupied by a creature, the spell fails, and your action and the spell slot are wasted.\n\nThe wall sheds bright light out to a range of 100 feet and dim light for an additional 100 feet. You and creatures you designate at the time you cast the spell can pass through and remain near the wall without harm. If another creature that can see the wall moves to within 20 feet of it or starts its turn there, the creature must succeed on a constitution saving throw or become blinded for 1 minute.\n\nThe wall consists of seven layers, each with a different color. When a creature attempts to reach into or pass through the wall, it does so one layer at a time through all the wall''s layers. As it passes or reaches through each layer, the creature must make a dexterity saving throw or be affected by that layer''s properties as described below.\n\nThe wall can be destroyed, also one layer at a time, in order from red to violet, by means specific to each layer. Once a layer is destroyed, it remains so for the duration of the spell. A rod of cancellation destroys a prismatic wall, but an antimagic field has no effect on it.\n\n***1. Red.*** The creature takes 10d6 fire damage on a failed save, or half as much damage on a successful one. While this layer is in place, nonmagical ranged attacks can''t pass through the wall. The layer can be destroyed by dealing at least 25 cold damage to it.\n\n***2. Orange.*** The creature takes 10d6 acid damage on a failed save, or half as much damage on a successful one. While this layer is in place, magical ranged attacks can''t pass through the wall. The layer is destroyed by a strong wind.\n\n***3. Yellow.*** The creature takes 10d6 lightning damage on a failed save, or half as much damage on a successful one. This layer can be destroyed by dealing at least 60 force damage to it.\n\n***4. Green.*** The creature takes 10d6 poison damage on a failed save, or half as much damage on a successful one. A passwall spell, or another spell of equal or greater level that can open a portal on a solid surface, destroys this layer.\n\n***5. Blue.*** The creature takes 10d6 cold damage on a failed save, or half as much damage on a successful one. This layer can be destroyed by dealing at least 25 fire damage to it.\n\n***6. Indigo.*** On a failed save, the creature is restrained. It must then make a constitution saving throw at the end of each of its turns. If it successfully saves three times, the spell ends. If it fails its save three times, it permanently turns to stone and is subjected to the petrified condition. The successes and failures don''t need to be consecutive; keep track of both until the creature collects three of a kind.\n\nWhile this layer is in place, spells can''t be cast through the wall. The layer is destroyed by bright light shed by a daylight spell or a similar spell of equal or higher level.\n\n***7. Violet.*** On a failed save, the creature is blinded. It must then make a wisdom saving throw at the start of your next turn. A successful save ends the blindness. If it fails that save, the creature is transported to another plane of the GM''s choosing and is no longer blinded. (Typically, a creature that is on a plane that isn''t its home plane is banished home, while other creatures are usually cast into the Astral or Ethereal planes.) This layer is destroyed by a dispel magic spell or a similar spell of equal or higher level that can end spells and magical effects.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{"type":"line","size":90}'::jsonb),
('shapechange', 'Shapechange', NULL, 'srd', 'private', 9, 'Transmutation', '1 action', 'Self', 'V, S, M (A jade circlet worth at least 1,500 gp, which you must place on your head before you cast the spell.)', 'Up to 1 hour', true, false, '{"Druid","Wizard","Psion"}', E'You assume the form of a different creature for the duration. The new form can be of any creature with a challenge rating equal to your level or lower. The creature can''t be a construct or an undead, and you must have seen the sort of creature at least once. You transform into an average example of that creature, one without any class levels or the Spellcasting trait.\n\nYour game statistics are replaced by the statistics of the chosen creature, though you retain your alignment and Intelligence, Wisdom, and Charisma scores. You also retain all of your skill and saving throw proficiencies, in addition to gaining those of the creature. If the creature has the same proficiency as you and the bonus listed in its statistics is higher than yours, use the creature''s bonus in place of yours. You can''t use any legendary actions or lair actions of the new form.\n\nYou assume the hit points and Hit Dice of the new form. When you revert to your normal form, you return to the number of hit points you had before you transformed. If you revert as a result of dropping to 0 hit points, any excess damage carries over to your normal form. As long as the excess damage doesn''t reduce your normal form to 0 hit points, you aren''t knocked unconscious.\n\nYou retain the benefit of any features from your class, race, or other source and can use them, provided that your new form is physically capable of doing so. You can''t use any special senses you have (for example, darkvision) unless your new form also has that sense. You can only speak if the creature can normally speak.\n\nWhen you transform, you choose whether your equipment falls to the ground, merges into the new form, or is worn by it. Worn equipment functions as normal. The GM determines whether it is practical for the new form to wear a piece of equipment, based on the creature''s shape and size. Your equipment doesn''t change shape or size to match the new form, and any equipment that the new form can''t wear must either fall to the ground or merge into your new form. Equipment that merges has no effect in that state.\n\nDuring this spell''s duration, you can use your action to assume a different form following the same restrictions and rules for the original form, with one exception: if your new form has more hit points than your current one, your hit points remain at their current value.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('storm-of-vengeance', 'Storm of Vengeance', NULL, 'srd', 'private', 9, 'Conjuration', '1 action', 'Sight', 'V, S', 'Up to 1 minute', true, false, '{"Druid"}', E'A churning storm cloud forms, centered on a point you can see and spreading to a radius of 360 feet. Lightning flashes in the area, thunder booms, and strong winds roar. Each creature under the cloud (no more than 5,000 feet beneath the cloud) when it appears must make a constitution saving throw. On a failed save, a creature takes 2d6 thunder damage and becomes deafened for 5 minutes.\n\nEach round you maintain concentration on this spell, the storm produces additional effects on your turn.\n\n***Round 2.*** Acidic rain falls from the cloud. Each creature and object under the cloud takes 1d6 acid damage.\n\n***Round 3.*** You call six bolts of lightning from the cloud to strike six creatures or objects of your choice beneath the cloud. A given creature or object can''t be struck by more than one bolt. A struck creature must make a dexterity saving throw. The creature takes 10d6 lightning damage on a failed save, or half as much damage on a successful one.\n\n***Round 4.*** Hailstones rain down from the cloud. Each creature under the cloud takes 2d6 bludgeoning damage.\n\n***Round 5-10.*** Gusts and freezing rain assail the area under the cloud. The area becomes difficult terrain and is heavily obscured. Each creature there takes 1d6 cold damage. Ranged weapon attacks in the area are impossible. The wind and rain count as a severe distraction for the purposes of maintaining concentration on spells. Finally, gusts of strong wind (ranging from 20 to 50 miles per hour) automatically disperse fog, mists, and similar phenomena in the area, whether mundane or magical.', NULL, 'CON', NULL, '2d6', 'Thunder', '{"9":"2d6"}'::jsonb, NULL, NULL, NULL, '{"type":"sphere","size":360}'::jsonb),
('time-stop', 'Time Stop', NULL, 'srd', 'private', 9, 'Transmutation', '1 action', 'Self', 'V', 'Instantaneous', false, false, '{"Sorcerer","Wizard","Psion"}', E'You briefly stop the flow of time for everyone but yourself. No time passes for other creatures, while you take 1d4 + 1 turns in a row, during which you can use actions and move as normal.\n\nThis spell ends if one of the actions you use during this period, or any effects that you create during this period, affects a creature other than you or an object being worn or carried by someone other than you. In addition, the spell ends if you move to a place more than 1,000 feet from the location where you cast it.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('true-polymorph', 'True Polymorph', NULL, 'srd', 'private', 9, 'Transmutation', '1 action', '30 feet', 'V, S, M (A drop of mercury, a dollop of gum arabic, and a wisp of smoke.)', 'Up to 1 hour', true, false, '{"Bard","Warlock","Wizard"}', E'Choose one creature or nonmagical object that you can see within range. You transform the creature into a different creature, the creature into an object, or the object into a creature (the object must be neither worn nor carried by another creature). The transformation lasts for the duration, or until the target drops to 0 hit points or dies. If you concentrate on this spell for the full duration, the transformation becomes permanent.\n\nShapechangers aren''t affected by this spell. An unwilling creature can make a wisdom saving throw, and if it succeeds, it isn''t affected by this spell.\n\n***Creature into Creature.*** If you turn a creature into another kind of creature, the new form can be any kind you choose whose challenge rating is equal to or less than the target''s (or its level, if the target doesn''t have a challenge rating). The target''s game statistics, including mental ability scores, are replaced by the statistics of the new form. It retains its alignment and personality.\n\nThe target assumes the hit points of its new form, and when it reverts to its normal form, the creature returns to the number of hit points it had before it transformed. If it reverts as a result of dropping to 0 hit points, any excess damage carries over to its normal form. As long as the excess damage doesn''t reduce the creature''s normal form to 0 hit points, it isn''t knocked unconscious.\n\nThe creature is limited in the actions it can perform by the nature of its new form, and it can''t speak, cast spells, or take any other action that requires hands or speech unless its new form is capable of such actions.\n\nThe target''s gear melds into the new form. The creature can''t activate, use, wield, or otherwise benefit from any of its equipment.\n\n***Object into Creature.*** You can turn an object into any kind of creature, as long as the creature''s size is no larger than the object''s size and the creature''s challenge rating is 9 or lower. The creature is friendly to you and your companions. It acts on each of your turns. You decide what action it takes and how it moves. The GM has the creature''s statistics and resolves all of its actions and movement.\n\nIf the spell becomes permanent, you no longer control the creature. It might remain friendly to you, depending on how you have treated it.\n\n***Creature into Object.*** If you turn a creature into an object, it transforms along with whatever it is wearing and carrying into that form. The creature''s statistics become those of the object, and the creature has no memory of time spent in this form, after the spell ends and it returns to its normal form.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('true-resurrection', 'True Resurrection', NULL, 'srd', 'private', 9, 'Necromancy', '1 hour', 'Touch', 'V, S, M (A sprinkle of holy water and diamonds worth at least 25,000gp, which the spell consumes.)', 'Instantaneous', false, false, '{"Cleric","Druid"}', E'You touch a creature that has been dead for no longer than 200 years and that died for any reason except old age. If the creature''s soul is free and willing, the creature is restored to life with all its hit points.\n\nThis spell closes all wounds, neutralizes any poison, cures all diseases, and lifts any curses affecting the creature when it died. The spell replaces damaged or missing organs and limbs.\n\nThe spell can even provide a new body if the original no longer exists, in which case you must speak the creature''s name. The creature then appears in an unoccupied space you choose within 10 feet of you.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('weird', 'Weird', NULL, 'srd', 'private', 9, 'Illusion', '1 action', '120 feet', 'V, S', 'Up to 1 minute', true, false, '{"Wizard","Psion"}', 'Drawing on the deepest fears of a group of creatures, you create illusory creatures in their minds, visible only to them. Each creature in a 30-foot-radius sphere centered on a point of your choice within range must make a wisdom saving throw. On a failed save, a creature becomes frightened for the duration. The illusion calls on the creature''s deepest fears, manifesting its worst nightmares as an implacable threat. At the start of each of the frightened creature''s turns, it must succeed on a wisdom saving throw or take 4d10 psychic damage. On a successful save, the spell ends for that creature.', NULL, 'WIS', NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{"type":"sphere","size":30}'::jsonb),
('wish', 'Wish', NULL, 'srd', 'private', 9, 'Conjuration', '1 action', 'Self', 'V', 'Instantaneous', false, false, '{"Sorcerer","Wizard"}', E'Wish is the mightiest spell a mortal creature can cast. By simply speaking aloud, you can alter the very foundations of reality in accord with your desires.\n\nThe basic use of this spell is to duplicate any other spell of 8th level or lower. You don''t need to meet any requirements in that spell, including costly components. The spell simply takes effect.\n\nAlternatively, you can create one of the following effects of your choice:\n\n- You create one object of up to 25,000 gp in value that isn''t a magic item. The object can be no more than 300 feet in any dimension, and it appears in an unoccupied space you can see on the ground.\n\n- You allow up to twenty creatures that you can see to regain all hit points, and you end all effects on them described in the greater restoration spell.\n\n- You grant up to ten creatures that you can see resistance to a damage type you choose.\n\n- You grant up to ten creatures you can see immunity to a single spell or other magical effect for 8 hours. For instance, you could make yourself and all your companions immune to a lich''s life drain attack.\n\n- You undo a single recent event by forcing a reroll of any roll made within the last round (including your last turn). Reality reshapes itself to accommodate the new result. For example, a wish spell could undo an opponent''s successful save, a foe''s critical hit, or a friend''s failed save. You can force the reroll to be made with advantage or disadvantage, and you can choose whether to use the reroll or the original roll.\n\nYou might be able to achieve something beyond the scope of the above examples. State your wish to the GM as precisely as possible. The GM has great latitude in ruling what occurs in such an instance; the greater the wish, the greater the likelihood that something goes wrong. This spell might simply fail, the effect you desire might only be partly achieved, or you might suffer some unforeseen consequence as a result of how you worded the wish. For example, wishing that a villain were dead might propel you forward in time to a period when that villain is no longer alive, effectively removing you from the game. Similarly, wishing for a legendary magic item or artifact might instantly transport you to the presence of the item''s current owner.\n\nThe stress of casting this spell to produce any effect other than duplicating another spell weakens you. After enduring that stress, each time you cast a spell until you finish a long rest, you take 1d10 necrotic damage per level of that spell. This damage can''t be reduced or prevented in any way. In addition, your Strength drops to 3, if it isn''t 3 or lower already, for 2d4 days. For each of those days that you spend resting and doing nothing more than light activity, your remaining recovery time decreases by 2 days. Finally, there is a 33 percent chance that you are unable to cast wish ever again if you suffer this stress.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('blade-ward', 'Blade Ward', NULL, 'srd', 'private', 0, 'Abjuration', '1 action', 'Self', 'V, S', 'Concentration, up to 1 minute', true, false, '{"Bard","Sorcerer","Warlock","Wizard","Psion"}', 'You extend your hand and trace a sigil of warding in the air. Until the start of your next turn, you have Resistance to Bludgeoning, Piercing, and Slashing damage dealt by weapon attacks.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('friends', 'Friends', NULL, 'srd', 'private', 0, 'Enchantment', '1 action', 'Self', 'S, M (a small amount of makeup applied to the face as this spell is cast)', 'Concentration, up to 1 minute', true, false, '{"Bard","Sorcerer","Warlock","Wizard","Psion"}', 'For the duration, you have Advantage on all Charisma checks directed at one creature of your choice that isn''t Hostile toward you. When the spell ends, the creature realizes that you used magic to influence its mood and becomes Hostile toward you. A creature prone to violence might attack you. Another creature might seek retribution in other ways depending on the nature of your interaction with it.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('mind-sliver', 'Mind Sliver', NULL, 'srd', 'private', 0, 'Enchantment', '1 action', '60 feet', 'V', '1 round', false, false, '{"Sorcerer","Warlock","Wizard","Psion"}', 'You drive a disorienting spike of psychic energy into the mind of one creature you can see within range. The target must succeed on an Intelligence saving throw or take 1d6 Psychic damage and subtract 1d4 from the next saving throw it makes before the end of your next turn.', 'The damage increases by 1d6 when you reach levels 5 (2d6), 11 (3d6), and 17 (4d6).', 'INT', NULL, NULL, 'Psychic', NULL, '{"1":"1d6","5":"2d6","11":"3d6","17":"4d6"}'::jsonb, NULL, NULL, NULL),
('telekinetic-fling', 'Telekinetic Fling', NULL, 'ua', 'private', 0, 'Evocation', '1 action', '60 feet', 'S', 'Instantaneous', false, false, '{"Psion"}', 'Choose one nonmagical object weighing 1 to 5 pounds within 10 feet of you that isn''t being worn or carried. You wreathe it in psionic energy and fire it at a creature within range. Make a ranged spell attack against the target. On a hit, the target takes 1d10 Force damage. On a hit or miss, the object falls to the ground undamaged.', 'The damage increases by 1d10 when you reach levels 5 (2d10), 11 (3d10), and 17 (4d10).', NULL, 'ranged', NULL, 'Force', NULL, '{"1":"1d10","5":"2d10","11":"3d10","17":"4d10"}'::jsonb, NULL, NULL, NULL),
('dissonant-whispers', 'Dissonant Whispers', NULL, 'srd', 'private', 1, 'Enchantment', '1 action', '60 feet', 'V', 'Instantaneous', false, false, '{"Bard","Psion"}', 'You whisper a discordant melody that only one creature of your choice within range can hear, wracking it with terrible pain. The target must make a Wisdom saving throw. On a failed save, it takes 3d6 Psychic damage and must immediately use its Reaction, if available, to move as far as its Speed allows away from you. The creature doesn''t move into obviously dangerous ground, such as a fire or a pit. On a successful save, the target takes half as much damage only.', 'The damage increases by 1d6 for each spell slot level above 1.', 'WIS', NULL, NULL, 'Psychic', '{"1":"3d6","2":"4d6","3":"5d6","4":"6d6","5":"7d6","6":"8d6","7":"9d6","8":"10d6","9":"11d6"}'::jsonb, NULL, NULL, NULL, NULL),
('life-siphon', 'Life Siphon', NULL, 'ua', 'private', 1, 'Evocation', '1 action', '120 feet', 'S', 'Instantaneous', false, false, '{"Psion"}', 'You fire an orb of psionic energy fueled by your life force at a creature you can see within range. Make a ranged spell attack against the target. On a hit, the target takes 1d10 Psychic damage and you can expend one Hit Point Die to increase the damage by 1d10.', 'The damage increases by 1d10 and the number of Hit Dice you can expend increases by one for each spell slot level above 1.', NULL, 'ranged', NULL, 'Psychic', '{"1":"1d10","2":"2d10","3":"3d10","4":"4d10","5":"5d10","6":"6d10","7":"7d10","8":"8d10","9":"9d10"}'::jsonb, NULL, NULL, NULL, NULL),
('tashas-hideous-laughter', 'Tasha''s Hideous Laughter', NULL, 'srd', 'private', 1, 'Enchantment', '1 action', '30 feet', 'V, S, M (tarts and a feather)', 'Concentration, up to 1 minute', true, false, '{"Bard","Wizard","Psion"}', 'One creature you can see within range perceives everything as hilariously funny and falls into fits of laughter if this spell affects it. The target must succeed on a Wisdom saving throw or fall Prone, becoming Incapacitated and unable to stand up for the duration. A creature with an Intelligence score of 4 or less isn''t affected. At the end of each of its turns, and each time it takes damage, the target can make another Wisdom saving throw. The target has Advantage on the saving throw if it''s triggered by damage. On a success, the spell ends.', NULL, 'WIS', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('tensers-floating-disk', 'Tenser''s Floating Disk', NULL, 'srd', 'private', 1, 'Conjuration', '1 action', '30 feet', 'V, S, M (a drop of mercury)', '1 hour', false, true, '{"Wizard","Psion"}', 'This spell creates a circular, horizontal plane of force, 3 feet in diameter and 1 inch thick, that floats 3 feet above the ground in an unoccupied space of your choice that you can see within range. The disk remains for the duration and can hold up to 500 pounds. If more weight is placed on it, the spell ends and everything on the disk falls to the ground. The disk is immobile while you are within 20 feet of it. If you move more than 20 feet away from it, the disk follows you so that it remains within 20 feet of you. It can move across uneven terrain, up or down stairs, slopes and the like, but it can''t cross an elevation change of 10 feet or more.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('crown-of-madness', 'Crown of Madness', NULL, 'srd', 'private', 2, 'Enchantment', '1 action', '120 feet', 'V, S', 'Concentration, up to 1 minute', true, false, '{"Bard","Sorcerer","Warlock","Wizard","Psion"}', 'One Humanoid of your choice that you can see within range must succeed on a Wisdom saving throw or have the Charmed condition for the duration. While Charmed, the target has a twisted crown of jagged iron appear on its head, and a madness glows within its eyes. The Charmed target must use its action before moving on each of its turns to make a melee attack against a creature other than itself that you mentally choose. The target can act normally on its turn if you choose no creature or if none are within its reach. On your subsequent turns, you must take a Magic action to maintain control of the target, or the spell ends. Also, the target can make a Wisdom saving throw at the end of each of its turns. On a success, the spell ends.', NULL, 'WIS', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('ectoplasmic-trail', 'Ectoplasmic Trail', NULL, 'ua', 'private', 2, 'Necromancy', '1 bonus action', 'Self', 'V, S', 'Instantaneous', false, false, '{"Psion","Warlock"}', 'You cloak yourself in spirits that leave ectoplasm in your wake until the end of your turn. While cloaked, you can move through occupied spaces as if they were Difficult Terrain, and moving doesn''t provoke Opportunity Attacks. If you end your turn in such a space, you are returned to the last unoccupied space you were in. While cloaked, whenever you enter the space of a creature, the creature becomes covered in ectoplasm until the end of your next turn. A creature covered in ectoplasm has its Speed reduced by 10 feet and takes 2d8 Necrotic damage at the start of its turn. A creature can be covered in ectoplasm only once during a turn.', 'While cloaked, your Speed increases by 10 feet for each spell slot level above 2.', NULL, NULL, NULL, 'Necrotic', '{"2":"2d8","3":"2d8","4":"2d8","5":"2d8","6":"2d8","7":"2d8","8":"2d8","9":"2d8"}'::jsonb, NULL, NULL, NULL, NULL),
('ego-whip', 'Ego Whip', NULL, 'ua', 'private', 2, 'Enchantment', '1 reaction, which you take when a creature you can see within 30 feet of yourself makes a Charisma-based ability check or saving throw', '120 feet', 'V', 'Instantaneous', false, false, '{"Psion"}', 'The creature makes a Charisma saving throw. On a failed save, the target must subtract 1d8 from the ability check or saving throw.', NULL, 'CHA', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('mind-spike', 'Mind Spike', NULL, 'srd', 'private', 2, 'Divination', '1 action', '60 feet', 'S', 'Concentration, up to 1 hour', true, false, '{"Sorcerer","Warlock","Wizard","Psion"}', 'You reach into the mind of one creature you can see within range. The target must make a Wisdom saving throw, taking 3d8 Psychic damage on a failed save, or half as much damage on a successful one. On a failed save, you also always know the target''s location until the spell ends, but only while the two of you are on the same plane of existence. While you have this knowledge, the target can''t become Hidden from you, and if it has the Invisible condition, it gains no benefit from that condition against you.', 'The damage increases by 1d8 for each spell slot level above 2.', 'WIS', NULL, NULL, 'Psychic', '{"2":"3d8","3":"4d8","4":"5d8","5":"6d8","6":"7d8","7":"8d8","8":"9d8","9":"10d8"}'::jsonb, NULL, NULL, NULL, NULL),
('phantasmal-force', 'Phantasmal Force', NULL, 'srd', 'private', 2, 'Illusion', '1 action', '60 feet', 'V, S, M (a bit of fleece)', 'Concentration, up to 1 minute', true, false, '{"Bard","Sorcerer","Wizard","Psion"}', 'You craft an illusion that takes root in the mind of a creature you can see within range. The target must succeed on an Intelligence saving throw or be affected by the spell for the duration. The illusion includes audio, visual, tactile, and olfactory elements, but it can''t create a sensation of pain. The target perceives the illusion as a real phenomenon. The illusion is tailored to the target, which ignores or rationalizes any sensory information that contradicts the illusion. While affected, the target treats the phantasm as real and rationalizes any illogical outcomes from interacting with it. While the spell lasts, the target takes 1d6 Psychic damage at the start of each of its turns from interacting with the illusion. The target can repeat the saving throw at the end of each of its turns, ending the spell on itself on a success.', NULL, 'INT', NULL, NULL, 'Psychic', NULL, NULL, NULL, NULL, NULL),
('tashas-mind-whip', 'Tasha''s Mind Whip', NULL, 'ua', 'private', 2, 'Enchantment', '1 action', '90 feet', 'V', 'Instantaneous', false, false, '{"Sorcerer","Wizard","Psion"}', 'You psychically lash out at one creature you can see within range. The target must make an Intelligence saving throw. On a failed save, the target takes 3d6 Psychic damage and can''t make Opportunity Attacks until the end of its next turn. On its next turn, it must choose whether it gets a move, an action, or a Bonus Action; it gets only one of the three. On a successful save, the target takes half as much damage only.', 'You can target one additional creature for each spell slot level above 2.', 'INT', NULL, NULL, 'Psychic', '{"2":"3d6","3":"3d6","4":"3d6","5":"3d6","6":"3d6","7":"3d6","8":"3d6","9":"3d6"}'::jsonb, NULL, NULL, NULL, NULL),
('bleeding-darkness', 'Bleeding Darkness', NULL, 'ua', 'private', 3, 'Evocation', '1 action', '60 feet', 'V, S, M (a vial of rare ink worth 50+ GP)', 'Concentration, up to 1 minute', true, false, '{"Psion","Warlock","Wizard"}', 'You create an inky void in a 10-foot-radius Sphere at a point you can see above yourself within range. When you cast the spell, magical Darkness pours from the sphere, filling a 10-foot-radius, 40-foot-tall Cylinder originating from the Sphere until the start of your next turn. The Cylinder is Difficult Terrain, and no light—magical or otherwise—can illuminate the area. When the Darkness appears, each creature in the area must succeed on a Constitution saving throw or take 3d8 Cold damage and have the Blinded condition until the end of its next turn. A creature also makes this save when it enters the spell''s area for the first time on a turn or ends its turn there. A creature makes this save only once per turn. Until the spell ends, you can take a Magic action to move the Sphere up to 20 feet horizontally and cause the Sphere to pour magical Darkness until the start of your next turn.', 'The damage increases by 1d8 for each spell slot level above 3.', 'CON', NULL, NULL, 'Cold', '{"3":"3d8","4":"4d8","5":"5d8","6":"6d8","7":"7d8","8":"8d8","9":"9d8"}'::jsonb, NULL, NULL, NULL, '{"type":"cylinder","size":10}'::jsonb),
('enemies-abound', 'Enemies Abound', NULL, 'srd', 'private', 3, 'Enchantment', '1 action', '120 feet', 'V, S', 'Concentration, up to 1 minute', true, false, '{"Bard","Psion","Sorcerer","Warlock","Wizard"}', 'You reach into the mind of one creature you can see and force it to make an Intelligence saving throw. A creature automatically succeeds if it is immune to being Frightened. On a failed save, the target loses the ability to distinguish friend from foe, regarding all creatures it can see as enemies until the spell ends. Each time the target takes damage, it can repeat the saving throw, ending the effect on itself on a success. Whenever the affected creature chooses another creature as a target, it must choose the target at random from among the creatures it can see within range of the attack, spell, or other ability it''s using. If an enemy provokes an Opportunity Attack from the affected creature, the creature must make that attack if it is able to.', NULL, 'INT', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('intellect-fortress', 'Intellect Fortress', NULL, 'ua', 'private', 3, 'Abjuration', '1 action', '30 feet', 'V', 'Concentration, up to 1 hour', true, false, '{"Artificer","Bard","Psion","Sorcerer","Warlock","Wizard"}', 'For the duration, you or one willing creature you can see within range has Resistance to Psychic damage as well as Advantage on Intelligence, Wisdom, and Charisma saving throws.', 'When you cast this spell using a spell slot of 4th level or higher, you can target one additional creature for each slot level above 3rd. The creatures must be within 30 feet of each other when you target them.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('summon-astral-entity', 'Summon Astral Entity', NULL, 'ua', 'private', 3, 'Conjuration', '1 action', '90 feet', 'V, S, M (a gem or crystal worth 300+ GP)', 'Concentration, up to 1 hour', true, false, '{"Psion","Sorcerer","Warlock"}', 'You call forth the spirit of a psionic entity. It manifests in an unoccupied space that you can see within range and uses the Psionic Spirit stat block. When you cast the spell, choose Crystal Entity, Ectoplasmic Entity, or Ghostly Entity. The creature resembles an astral entity of that kind, which determines certain details in its stat block. The creature disappears when it drops to 0 Hit Points or when the spell ends. The creature is an ally to you and your allies. In combat, the creature shares your Initiative count, but it takes its turn immediately after yours. It obeys your verbal commands (no action required by you). If you don''t issue any, it takes the Dodge action and uses its movement to avoid danger.', 'Use the spell slot''s level for the spell''s level in the stat block.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('telekinetic-crush', 'Telekinetic Crush', NULL, 'ua', 'private', 3, 'Transmutation', '1 action', '120 feet', 'V', 'Instantaneous', false, false, '{"Psion","Sorcerer","Warlock"}', 'You create a field of crushing telekinetic force in a 30-foot Cube within range. Each creature in the area makes a Strength saving throw. On a failed save, the target takes 5d6 Force damage and has the Prone condition. On a successful save, the target takes half as much damage only.', 'The damage increases by 1d6 for each spell slot level above 3.', 'STR', NULL, NULL, 'Force', '{"3":"5d6","4":"6d6","5":"7d6","6":"8d6","7":"9d6","8":"10d6","9":"11d6"}'::jsonb, NULL, NULL, NULL, '{"type":"cube","size":30}'::jsonb),
('charm-monster', 'Charm Monster', NULL, 'srd', 'private', 4, 'Enchantment', '1 action', '30 feet', 'V, S', '1 hour', false, false, '{"Bard","Druid","Sorcerer","Warlock","Wizard","Psion"}', 'You attempt to charm a creature you can see within range. It must make a Wisdom saving throw, and it does so with Advantage if you or your allies are fighting it. If it fails the save, it has the Charmed condition for the duration or until you or your allies damage it. The Charmed creature is friendly to you. When the spell ends, the creature knows it was Charmed by you.', 'You can target one additional creature for each spell slot level above 4.', 'WIS', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('life-inversion-field', 'Life Inversion Field', NULL, 'ua', 'private', 4, 'Abjuration', '1 action', 'Self', 'V, S', 'Concentration, up to 1 minute', true, false, '{"Cleric","Psion","Sorcerer"}', 'An aura radiates from you in a 30-foot Emanation for the duration. When you create the aura, you regain 4d8 Hit Points. Whenever you regain Hit Points, you can choose a creature you can see in the aura and force it to make a Constitution saving throw. On a failed save, the creature takes Necrotic damage equal to half the amount of Hit Points you regained (round up). A creature makes this save only once per turn.', 'The healing increases by 1d8 for each spell slot level above 4.', 'CON', NULL, NULL, 'Necrotic', NULL, NULL, '4d8', '{"4":"4d8","5":"5d8","6":"6d8","7":"7d8","8":"8d8","9":"9d8"}'::jsonb, NULL),
('raulothims-psychic-lance', 'Raulothim''s Psychic Lance', NULL, 'ua', 'private', 4, 'Enchantment', '1 action', '120 feet', 'V', 'Instantaneous', false, false, '{"Bard","Psion","Sorcerer","Warlock","Wizard"}', 'You unleash a shimmering lance of psychic power from your forehead at a creature that you can see within range. Alternatively, you can utter a creature''s name (a pseudonym, title, or nickname doesn''t work). If the named target is within range, it becomes the spell''s target even if you can''t see it. If the named target isn''t within range or you use an invalid name, the lance dissipates without effect. The target must make an Intelligence saving throw. On a failed save, the target takes 7d6 Psychic damage and has the Incapacitated condition until the start of your next turn. On a successful save, the target takes half as much damage only.', 'The damage increases by 1d6 for each spell slot level above 4.', 'INT', NULL, NULL, 'Psychic', '{"4":"7d6","5":"8d6","6":"9d6","7":"10d6","8":"11d6","9":"12d6"}'::jsonb, NULL, NULL, NULL, NULL),
('summon-aberration', 'Summon Aberration', NULL, 'srd', 'private', 4, 'Conjuration', '1 action', '90 feet', 'V, S, M (a pickled tentacle and an eyeball in a platinum-inlaid vial worth 400+ GP)', 'Concentration, up to 1 hour', true, false, '{"Warlock","Wizard","Psion"}', 'You call forth an aberrant spirit. It manifests in an unoccupied space that you can see within range and uses the Aberrant Spirit stat block. When you cast the spell, choose Beholderkin, Slaad, or Star Spawn. The creature resembles an aberration of that kind, which determines certain details in its stat block. The creature disappears when it drops to 0 Hit Points or when the spell ends. The creature is an ally to you and your allies. In combat, the creature shares your Initiative count, but it takes its turn immediately after yours. It obeys your verbal commands (no action required by you). If you don''t issue any, it takes the Dodge action and uses its movement to avoid danger.', 'Use the spell slot''s level for the spell''s level in the stat block.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('rarys-telepathic-bond', 'Rary''s Telepathic Bond', NULL, 'srd', 'private', 5, 'Divination', '1 action', '30 feet', 'V, S, M (pieces of eggshell from two different kinds of creatures)', '1 hour', false, true, '{"Wizard","Psion"}', 'You forge a telepathic link among up to eight willing creatures of your choice within range, psychically linking each creature to all the others for the duration. Creatures with an Intelligence score of 2 or less aren''t affected by this spell. Until the spell ends, the targets can communicate telepathically through the bond whether or not they have a common language. The communication is possible over any distance, though it can''t extend to other planes of existence.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('synaptic-static', 'Synaptic Static', NULL, 'srd', 'private', 5, 'Enchantment', '1 action', '120 feet', 'V, S', 'Instantaneous', false, false, '{"Bard","Sorcerer","Warlock","Wizard","Psion"}', 'You choose a point within range and cause psychic energy to explode there. Each creature in a 20-foot-radius Sphere centered on that point must make an Intelligence saving throw. A creature takes 8d6 Psychic damage on a failed save, or half as much damage on a successful one. On a failed save, a target also has muddled thoughts for 1 minute. During that time, it rolls a d6 and subtracts the number rolled from all attack rolls and ability checks, as well as Constitution saving throws to maintain Concentration. The target can make an Intelligence saving throw at the end of each of its turns, ending the effect on itself on a success.', NULL, 'INT', NULL, NULL, 'Psychic', '{"5":"8d6","6":"8d6","7":"8d6","8":"8d6","9":"8d6"}'::jsonb, NULL, NULL, NULL, '{"type":"sphere","size":20}'::jsonb),
('mental-prison', 'Mental Prison', NULL, 'srd', 'private', 6, 'Illusion', '1 action', '60 feet', 'S', '1 minute', false, false, '{"Bard","Psion","Sorcerer","Wizard"}', 'You attempt to bind a creature within an illusory cell that only it perceives. One creature you can see within range must make an Intelligence saving throw. The target succeeds automatically if it is immune to being Charmed. On a successful save, the target takes 5d10 Psychic damage, and the spell ends. On a failed save, the target takes 5d10 Psychic damage, and you make the area immediately around the target''s space appear dangerous to it in some way. Whatever form the illusion takes, the target can''t see or hear anything beyond it and is Restrained for the spell''s duration. If the target is moved out of the illusion, makes a melee attack through it, or reaches any part of its body through it, the target takes 10d10 Psychic damage, and the spell ends.', NULL, 'INT', NULL, NULL, 'Psychic', '{"6":"5d10","7":"5d10","8":"5d10","9":"5d10"}'::jsonb, NULL, NULL, NULL, NULL),
('ottos-irresistible-dance', 'Otto''s Irresistible Dance', NULL, 'srd', 'private', 6, 'Enchantment', '1 action', '30 feet', 'V', 'Concentration, up to 1 minute', true, false, '{"Bard","Wizard","Psion"}', 'Choose one creature that you can see within range. The target begins a comic dance in place: shuffling, tapping its feet, and capering for the duration. Creatures that can''t be Charmed are immune to this spell. A dancing creature must use all its movement to dance without leaving its space and has Disadvantage on Dexterity saving throws and attack rolls. While the target is affected by this spell, other creatures have Advantage on attack rolls against it. As an action, a dancing creature makes a Wisdom saving throw to regain control of itself. On a successful save, the spell ends.', NULL, 'WIS', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
('psionic-blast', 'Psionic Blast', NULL, 'ua', 'private', 6, 'Evocation', '1 action', 'Self', 'V, S, M (a small crystal)', 'Instantaneous', false, false, '{"Psion","Wizard"}', 'You unleash a concussive burst of psionic energy. Each creature in a 60-foot Cone originating from you makes an Intelligence saving throw. On a failed save, the creature takes 6d8 Psychic damage and has the Stunned condition until the start of your next turn. On a successful save, the creature takes half as much damage only.', 'The damage increases by 1d8 for each spell slot level above 6.', 'INT', NULL, NULL, 'Psychic', '{"6":"6d8","7":"7d8","8":"8d8","9":"9d8"}'::jsonb, NULL, NULL, NULL, '{"type":"cone","size":60}'::jsonb)
